"use strict";parserFactory.register("wtnovels.com",()=>new WtnovelsParser);class WtnovelsParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e,t){let r=this.extractPartialChapterList(e),l=this.getUrlsOfTocPages(e);return(await this.getChaptersFromAllTocPages(r,this.extractPartialChapterList,l,t)).reverse()}extractPartialChapterList(e){return[...e.querySelectorAll("div.chapters-list a")].map(e=>({sourceUrl:e.href,title:e.querySelector("h3").textContent,isIncludeable:null==e.querySelector(".chapter-paid-points")}))}getUrlsOfTocPages(e){let t=[],r=[...e.querySelectorAll("nav.cgl-pagination a.cgl-page")].pop()?.href;if(r){let e=r.split("/");if(e.length>=7){let r=parseInt(e[6]);for(let l=2;l<=r;++l)e[6]=l,t.push(e.join("/"))}}return t}extractTitleImpl(e){return e.querySelector("h1.novel-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".novel-header")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".novel-summary-initial")]}}